import{_ as a,o as n,c as e,a2 as o}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Changelog Management","description":"Maintaining a changelog that tracks user-facing changes, using conventional commits and tools like git-cliff to automate changelog generation for each release.","frontmatter":{"title":"Changelog Management","description":"Maintaining a changelog that tracks user-facing changes, using conventional commits and tools like git-cliff to automate changelog generation for each release."},"headers":[],"relativePath":"learn/project/15-production-polish/12-changelog-management.md","filePath":"learn/project/15-production-polish/12-changelog-management.md"}'),l={name:"learn/project/15-production-polish/12-changelog-management.md"};function t(p,s,c,i,r,y){return n(),e("div",null,[...s[0]||(s[0]=[o(`<h1 id="changelog-management" tabindex="-1">Changelog Management <a class="header-anchor" href="#changelog-management" aria-label="Permalink to &quot;Changelog Management&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to maintain a CHANGELOG.md following the Keep a Changelog conventions</li><li>How to use conventional commits and git-cliff to automate changelog generation</li><li>Techniques for categorizing changes as added, changed, fixed, or removed for clear communication</li></ul></blockquote><p>Users want to know what changed in each release. Did you fix the bug they reported? Is there a new feature they can try? Will anything break when they upgrade? A well-maintained changelog answers these questions at a glance. In this subchapter, you will set up both the conventions and the tooling to keep your changelog accurate with minimal effort.</p><h2 id="the-keep-a-changelog-format" tabindex="-1">The Keep a Changelog Format <a class="header-anchor" href="#the-keep-a-changelog-format" aria-label="Permalink to &quot;The Keep a Changelog Format&quot;">​</a></h2><p>The <a href="https://keepachangelog.com/" target="_blank" rel="noreferrer">Keep a Changelog</a> convention is the most widely used format. Here is what it looks like:</p><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;"># Changelog</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">All notable changes to this project will be documented in this file.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">The format is based on </span><span style="color:#B4BEFE;">[</span><span style="color:#B4BEFE;">Keep a Changelog</span><span style="color:#B4BEFE;">]</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;">https://keepachangelog.com/</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">and this project adheres to </span><span style="color:#B4BEFE;">[</span><span style="color:#B4BEFE;">Semantic Versioning</span><span style="color:#B4BEFE;">]</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;">https://semver.org/</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;">.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## </span><span style="color:#B4BEFE;">[</span><span style="color:#B4BEFE;">Unreleased</span><span style="color:#B4BEFE;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Added</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Shell completion generation for bash, zsh, and fish</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Fixed</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Config file parsing now handles comments correctly</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## </span><span style="color:#B4BEFE;">[</span><span style="color:#B4BEFE;">0.2.0</span><span style="color:#B4BEFE;">]</span><span style="color:#FAB387;"> - 2026-03-10</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Added</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Multi-provider support (Anthropic, OpenAI, Ollama)</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Project-level configuration with </span><span style="color:#A6E3A1;">\`.agent.toml\`</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Structured logging with the </span><span style="color:#A6E3A1;">\`tracing\`</span><span style="color:#CDD6F4;"> crate</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Changed</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Default model updated to claude-sonnet-4-20250514</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Config file format migrated from JSON to TOML</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Fixed</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Agent no longer crashes on malformed LLM responses</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Shell command timeout now works correctly on Linux</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Removed</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Deprecated </span><span style="color:#A6E3A1;">\`--api-key\`</span><span style="color:#CDD6F4;"> CLI flag (use environment variable instead)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">## </span><span style="color:#B4BEFE;">[</span><span style="color:#B4BEFE;">0.1.0</span><span style="color:#B4BEFE;">]</span><span style="color:#FAB387;"> - 2026-02-15</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">### Added</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Initial release with Anthropic provider support</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Interactive REPL mode</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> File read/write tools</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Shell command execution</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> Basic error handling</span></span></code></pre></div><p>The structure is simple: each version has dated sections grouped by change type. The <code>[Unreleased]</code> section at the top collects changes that have not been released yet.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python projects use the same Keep a Changelog format (or similar). If you have maintained a <code>CHANGELOG.md</code> or <code>HISTORY.rst</code> for a Python package, this will be familiar. The difference in the Rust ecosystem is that tools like <code>git-cliff</code> can fully automate changelog generation from commit messages, whereas Python&#39;s equivalents like <code>towncrier</code> require separate &quot;news fragments&quot; for each change.</p></div><h2 id="conventional-commits" tabindex="-1">Conventional Commits <a class="header-anchor" href="#conventional-commits" aria-label="Permalink to &quot;Conventional Commits&quot;">​</a></h2><p>Automated changelog generation requires structured commit messages. The <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a> specification gives you that structure:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>&lt;type&gt;(&lt;scope&gt;): &lt;description&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[optional body]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[optional footer]</span></span></code></pre></div><p>Common types and how they map to changelog categories:</p><table tabindex="0"><thead><tr><th>Commit Type</th><th>Changelog Category</th><th>Example</th></tr></thead><tbody><tr><td><code>feat</code></td><td>Added</td><td><code>feat(tools): add grep tool for code search</code></td></tr><tr><td><code>fix</code></td><td>Fixed</td><td><code>fix(shell): handle timeout on long-running commands</code></td></tr><tr><td><code>perf</code></td><td>Changed</td><td><code>perf(parser): reduce JSON parsing allocations by 40%</code></td></tr><tr><td><code>refactor</code></td><td>Changed</td><td><code>refactor(config): simplify layered config merging</code></td></tr><tr><td><code>docs</code></td><td>(usually excluded)</td><td><code>docs: update installation guide for Homebrew</code></td></tr><tr><td><code>test</code></td><td>(usually excluded)</td><td><code>test: add integration tests for multi-turn conversations</code></td></tr><tr><td><code>chore</code></td><td>(usually excluded)</td><td><code>chore: update dependencies</code></td></tr><tr><td><code>feat!</code> or <code>BREAKING CHANGE</code></td><td>(highlighted)</td><td><code>feat!: change config format from JSON to TOML</code></td></tr></tbody></table><p>The scope is optional but useful for filtering changes to specific components. The <code>!</code> after the type (or <code>BREAKING CHANGE</code> in the footer) marks breaking changes that warrant a major version bump.</p><h2 id="setting-up-git-cliff" tabindex="-1">Setting Up git-cliff <a class="header-anchor" href="#setting-up-git-cliff" aria-label="Permalink to &quot;Setting Up git-cliff&quot;">​</a></h2><p><code>git-cliff</code> reads your commit history, applies conventional commit parsing, and generates a changelog. Install it:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> git-cliff</span></span></code></pre></div><p>Create a configuration file <code>cliff.toml</code> in your project root:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">changelog</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">header </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;"># Changelog</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">All notable changes to this project will be documented in this file.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">The format is based on [Keep a Changelog](https://keepachangelog.com/),</span></span>
<span class="line"><span style="color:#A6E3A1;">and this project adheres to [Semantic Versioning](https://semver.org/).</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">body </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">{% if version %}\\</span></span>
<span class="line"><span style="color:#A6E3A1;">    ## [{{ version | trim_start_matches(pat=&quot;v&quot;) }}] - {{ timestamp | date(format=&quot;%Y-%m-%d&quot;) }}</span></span>
<span class="line"><span style="color:#A6E3A1;">{% else %}\\</span></span>
<span class="line"><span style="color:#A6E3A1;">    ## [Unreleased]</span></span>
<span class="line"><span style="color:#A6E3A1;">{% endif %}\\</span></span>
<span class="line"><span style="color:#A6E3A1;">{% for group, commits in commits | group_by(attribute=&quot;group&quot;) %}</span></span>
<span class="line"><span style="color:#A6E3A1;">    ### {{ group | upper_first }}</span></span>
<span class="line"><span style="color:#A6E3A1;">    {% for commit in commits %}</span></span>
<span class="line"><span style="color:#A6E3A1;">        - {% if commit.scope %}**{{ commit.scope }}**: {% endif %}\\</span></span>
<span class="line"><span style="color:#A6E3A1;">            {{ commit.message | upper_first }}\\</span></span>
<span class="line"><span style="color:#A6E3A1;">            {% if commit.breaking %} (**BREAKING**){% endif %}\\</span></span>
<span class="line"><span style="color:#A6E3A1;">    {% endfor %}</span></span>
<span class="line"><span style="color:#A6E3A1;">{% endfor %}</span><span style="color:#F5C2E7;">\\n</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">trim </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">git</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">conventional_commits </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#CDD6F4;">filter_unconventional </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#CDD6F4;">split_commits </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#CDD6F4;">commit_parsers </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^feat&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> group </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Added&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^fix&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> group </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Fixed&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^perf&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> group </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Changed&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^refactor&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> group </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Changed&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^doc&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> group </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Documentation&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^style&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> skip </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^test&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> skip </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^chore&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> skip </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#CDD6F4;"> message </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;^ci&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> skip </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">protect_breaking_commits </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#CDD6F4;">filter_commits </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#CDD6F4;">tag_pattern </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;v[0-9].*&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">sort_commits </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;oldest&quot;</span></span></code></pre></div><p>Generate the changelog:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Generate full changelog</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git-cliff</span><span style="color:#A6E3A1;"> -o</span><span style="color:#A6E3A1;"> CHANGELOG.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Generate changelog for just the latest release</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git-cliff</span><span style="color:#A6E3A1;"> --latest</span><span style="color:#A6E3A1;"> -o</span><span style="color:#A6E3A1;"> CHANGELOG.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Preview what the next release would look like</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git-cliff</span><span style="color:#A6E3A1;"> --unreleased</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Generate changelog between two tags</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git-cliff</span><span style="color:#A6E3A1;"> v0.1.0..v0.2.0</span></span></code></pre></div><h2 id="integrating-with-the-release-pipeline" tabindex="-1">Integrating with the Release Pipeline <a class="header-anchor" href="#integrating-with-the-release-pipeline" aria-label="Permalink to &quot;Integrating with the Release Pipeline&quot;">​</a></h2><p>Add changelog generation to your GitHub Actions release workflow:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Add this step to your release job in .github/workflows/release.yml</span></span>
<span class="line"><span style="color:#9399B2;">-</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Generate release notes</span></span>
<span class="line"><span style="color:#89B4FA;">  run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">    cargo install git-cliff</span></span>
<span class="line"><span style="color:#A6E3A1;">    # Generate notes for just this release</span></span>
<span class="line"><span style="color:#A6E3A1;">    git-cliff --latest --strip header &gt; release-notes.md</span></span>
<span class="line"><span style="color:#A6E3A1;">    cat release-notes.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">-</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Update CHANGELOG.md</span></span>
<span class="line"><span style="color:#89B4FA;">  run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">    git-cliff -o CHANGELOG.md</span></span>
<span class="line"><span style="color:#A6E3A1;">    git config user.name &quot;github-actions[bot]&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">    git config user.email &quot;github-actions[bot]@users.noreply.github.com&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">    git add CHANGELOG.md</span></span>
<span class="line"><span style="color:#A6E3A1;">    git commit -m &quot;chore: update CHANGELOG.md for \${{ github.ref_name }}&quot; || true</span></span>
<span class="line"><span style="color:#A6E3A1;">    git push origin HEAD:main || true</span></span></code></pre></div><p>This generates release notes for the GitHub Release page and updates the <code>CHANGELOG.md</code> file in the repository.</p><h2 id="writing-good-commit-messages" tabindex="-1">Writing Good Commit Messages <a class="header-anchor" href="#writing-good-commit-messages" aria-label="Permalink to &quot;Writing Good Commit Messages&quot;">​</a></h2><p>The quality of your changelog depends entirely on the quality of your commit messages. Here are practical examples:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Good: specific, describes the user-facing change</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> commit</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> &quot;feat(tools): add grep tool for searching code with regex patterns&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Bad: vague, describes implementation not behavior</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> commit</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> &quot;feat: add new tool&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Good: explains what was broken and how it is fixed</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> commit</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> &quot;fix(shell): prevent command timeout from killing the agent process</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">The shell tool was using SIGKILL to terminate timed-out commands, which</span></span>
<span class="line"><span style="color:#A6E3A1;">also killed the agent&#39;s child process group. Now uses SIGTERM with a</span></span>
<span class="line"><span style="color:#A6E3A1;">grace period before escalating to SIGKILL.&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Good: breaking change clearly marked</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> commit</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> &quot;feat!(config): migrate configuration from JSON to TOML</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">BREAKING CHANGE: Config files must be renamed from .agent.json to</span></span>
<span class="line"><span style="color:#A6E3A1;">.agent.toml and converted to TOML format. Run &#39;agent config migrate&#39;</span></span>
<span class="line"><span style="color:#A6E3A1;">to convert automatically.&quot;</span></span></code></pre></div><h2 id="enforcing-commit-conventions" tabindex="-1">Enforcing Commit Conventions <a class="header-anchor" href="#enforcing-commit-conventions" aria-label="Permalink to &quot;Enforcing Commit Conventions&quot;">​</a></h2><p>Use a Git hook to validate commit messages before they are accepted:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;font-style:italic;">#!/bin/sh</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># .githooks/commit-msg</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">commit_msg</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">$(</span><span style="color:#89B4FA;font-style:italic;">cat</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#EBA0AC;font-style:italic;">$1</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Conventional commit pattern</span></span>
<span class="line"><span style="color:#CDD6F4;">pattern</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;^(feat|fix|docs|style|refactor|perf|test|chore|ci|build|revert)(\\(.+\\))?(!)?: .{1,}&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#94E2D5;"> !</span><span style="color:#F38BA8;font-style:italic;"> echo</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$commit_msg</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> grep</span><span style="color:#A6E3A1;"> -qE</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$pattern</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">;</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;ERROR: Commit message does not follow Conventional Commits format.&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Expected: &lt;type&gt;(&lt;scope&gt;): &lt;description&gt;&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Example:  feat(tools): add grep tool for code search&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Valid types: feat, fix, docs, style, refactor, perf, test, chore, ci, build, revert&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    exit</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span></code></pre></div><p>Enable the hook:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> config</span><span style="color:#A6E3A1;"> core.hooksPath</span><span style="color:#A6E3A1;"> .githooks</span></span></code></pre></div><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Many Rust CLI tools including <code>ripgrep</code> and <code>bat</code> maintain hand-written changelogs that are meticulously organized by category. Larger projects with more contributors tend to automate with tools like <code>git-cliff</code> or <code>release-plz</code>. Claude Code&#39;s changelog is maintained as part of its release process within Anthropic&#39;s internal systems. The consensus in the ecosystem is that automated changelogs from conventional commits produce good-enough results for most projects, with the option to manually edit before publishing.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Follow the Keep a Changelog format with sections for Added, Changed, Fixed, and Removed under each version heading -- this is the format users expect and understand.</li><li>Adopt Conventional Commits (<code>feat:</code>, <code>fix:</code>, <code>perf:</code>, etc.) for structured commit messages that enable automated changelog generation and semantic version bumping.</li><li>Use <code>git-cliff</code> to generate changelogs from commit history, configured with a <code>cliff.toml</code> that maps commit types to changelog categories and filters out non-user-facing changes.</li><li>Integrate changelog generation into your CI release pipeline so that every tagged release automatically updates <code>CHANGELOG.md</code> and generates release notes for the GitHub Release page.</li><li>Enforce commit message conventions with a Git hook that rejects non-conforming messages, ensuring the raw material for your changelog is consistently structured.</li></ul>`,36)])])}const h=a(l,[["render",t]]);export{g as __pageData,h as default};
